// panelArgs serializes fbPanel's config (field key, type, current operator,
// target chip index, active preset) for the Alpine factory.
func panelArgs(field FieldDef, cond *filterq.Condition, chipIdx int) string {
	// Default to the field's first operator; guard against a misconfigured field
	// with no operators so rendering can't panic on an out-of-range index.
	op := ""
	if ops := field.operators(); len(ops) > 0 {
		op = string(ops[0])
	}
	preset := ""
	if cond != nil {
		op = string(cond.Op)
		if p, isPreset := cond.Preset(); isPreset {
			preset = string(p)
		}
	}
	s, err := templ.JSONString(map[string]any{
		"field":  field.Key,
		"type":   string(field.Type),
		"op":     op,
		"chip":   chipIdx,
		"preset": preset,
	})
	if err != nil {
		return "{}"
	}
	return s
}

// explicitDates returns the condition's date values unless they are symbolic
// (preset) — presets prefill nothing, they re-resolve on the server.
func explicitDates(cond *filterq.Condition) []string {
	if cond == nil {
		return nil
	}
	if _, isPreset := cond.Preset(); isPreset {
		return nil
	}
	return cond.Values
}

func numberValue(cond *filterq.Condition, i int) string {
	if cond == nil || len(cond.Values) <= i {
		return ""
	}
	return cond.Values[i]
}

